var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"관리부장님. 부탁하셨던 일정 산출이 끝났습니다.","JPN":"管理部長様、申し付けられていた日程の算出が終わりました。","ENG":"Manager, I've completed drafting the schedule per your request.","TWN":"管理部長，您委託的日程算出來了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"청소만큼 일정도 무척 깔끔하게 정리해 주셨네요. 바쁠 텐데 고마워요.","JPN":"掃除も日程も、とても綺麗に整理してくれましたね。忙しいのにありがとうございます。","ENG":"This is as immaculate as your cleaning work. Thank you for this. I'm sure you're busy with other things.","TWN":"做得很好，謝謝妳了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"별말씀을요. 주인님의 사업에 이바지할 수 있게 되어 영광입니다.","JPN":"とんでもございません。ご主人様の事業に貢献できて光栄です。","ENG":"You're most welcome. It's my honor to contribute to the Master's business.","TWN":"不會，能幫到主人，我感到無限光榮。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 주인님께 드릴 커피를 내렸습니다만, 관리부장님께서도 어떠신가요?","JPN":"ご主人様に差し上げるコーヒーを淹れたのですが、管理部長様もいかがでしょうか。","ENG":"I've also brewed some coffee for the Master. Would you care for a cup yourself?","TWN":"對了，我幫主人沖了杯現磨咖啡，您要喝點嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 한 잔 부탁드릴게요. 저번에 입수하셨다던 좋은 원두가 어떤 맛일지 궁금하네요.","JPN":"それでは、お言葉に甘えて。この前入手したコーヒー豆の味が気になりますね。","ENG":"Yes, please. I can't wait to taste the good beans you got the other day.","TWN":"那也給我來一杯吧，聽說老闆上次入手了不錯的咖啡豆，也不知道味道如何。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 시중에서는 구하기 어려운 물건이니 모쪼록 기대해 주시길.","JPN":"はい。通常のお店では手に入らないものですので、どうか楽しみにしてください。","ENG":"It's hard to find on the market. I'm sure you'll enjoy it.","TWN":"好的，那是在市面上不容易買到的，敬請期待吧。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......나도 커피 잘 탈 수 있는데.","JPN":"……私だって美味しいコーヒーを淹れられるのに。","ENG":"I can make a mean cup of coffee, too.","TWN":"……我沖的咖啡也很好喝。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"동경하던 관리부장 옆자리를 처음 보는 사람이 가로채서 분한가요?","JPN":"憧れの管理部長の一番弟子の座を横取りされて悔しいんですか？","ENG":"Are you upset because some stranger won over your admired Manager's heart instead?","TWN":"妳崇拜的管理部長，就這麼被剛來的人搶走了，是不是覺得很氣憤？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그런 레나 양에게 딱 맞는 특제 부적이 마침 할인가로 나와 있습니다.","JPN":"そんなレナにピッタリな特製お守りを割引価格で提供できますよ。","ENG":"I've got just the talisman for you. And it's on sale, too.","TWN":"這裡有一個非常適合蕾娜的特製護身符在打折哦。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......효과 확실해?","JPN":"……効果は確かなの？","ENG":"You sure it will work?","TWN":"……效果如何？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"레나님! 이것 좀 보십셔!","JPN":"レナ様！　これを見てほしいっす！","ENG":"Ms. Lena! Look at this!","TWN":"蕾娜小姐！妳看看這個！"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L20_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"브리핑 룸 구석에서 찾은 맥주 박스임다! 이거면 배터지게 마실 수 있을 검다!","JPN":"会議室の隅で見つけたビールのケースっす！　こんだけあるならみんなでお腹がいっぱいになるまで飲めそうっす！","ENG":"I found a six pack in the corner of the briefing room! It's enough for you to drink all night!","TWN":"這個是我在簡報室角落找到的啤酒箱子！這些可以喝到撐了！"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"앗?! 모네 너, 그 맥주 어디서 가져 온 거야?!","JPN":"えっ！？　モネ、そのビールどこから持ってきたの！？","ENG":"Huh?! Mone, where did you find that beer?!","TWN":"額？！莫妮，那啤酒是從哪裡來的？！"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"레나 양...... 설마 회사에선 마시지 말라고 그렇게 말했는데 또......","JPN":"レナさん……会社では飲まないようにとあれだけ言ったのにまた……","ENG":"Lena... I told you not to drink on duty... yet here you are again...","TWN":"蕾娜……我說過多少次不要在公司裡喝酒，妳又……"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"관리부장님! 그게, 그게 말이죠!","JPN":"管理部長！　いや、違います！","ENG":"Manager! I-it's not what it looks like!","TWN":"管理部長！那、那是因為！"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"모네 너, 나중에 두고 봐!","JPN":"モネ！　あとで話があるからね！","ENG":"You'll pay for this, Mone!","TWN":"莫妮，妳給我等著瞧！"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"앗? 레나님! 이거 안 드심까?","JPN":"あれ？　レナ様？　これ飲まないんっすか？","ENG":"Huh? Ms. Lena! Aren't you gonna drink this, ma'am?","TWN":"啊？蕾娜小姐！妳不喝了嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"모, 몰라!! 난 무알콜만 마신다구!","JPN":"ち、違うって！！　私はノンアルコールしか飲まないの！","ENG":"N-no! I only drink non-alcoholic beer!","TWN":"不、不喝！！我只喝沒有酒精的！"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 금세 잘 어울리는군.","JPN":"ハハハ、ずいぶん仲良くなったものだな。","ENG":"Hah hah, look at them get along so well already.","TWN":"哈哈，這麼快就混成一片了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이 또한 나의 뛰어난 영도력이 이루어낸 결과지.","JPN":"これもまた、私の優れた指導力が成し遂げた結果に違いない。","ENG":"This is all thanks to my outstanding leadership.","TWN":"這也是拜我卓越的領導能力啊。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"제가 보기에는 단순히 저 메이드 때문인 것 같은데요.","JPN":"普通にあのメイドのおかげだと思いますが。","ENG":"It looks like it's all thanks to that maid, actually.","TWN":"我怎麼覺得是因為那個女僕呢。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"낯선 사람을 경계하던 애는 자기 입사 기념이라면서 수제 생크림 케이크로 무너뜨렸고,","JPN":"新人だからと警戒していた子には、契約記念の手作りケーキを渡して機嫌を取って、","ENG":"She managed to tame that wild beast of a kid with a welcome cake.","TWN":"那個怕生的孩子說是自己的入職紀念，就將手工奶油蛋糕給砸了，"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"미래전략실장에게는 매일 동화책을 읽어 주면서 환심을 사고,","JPN":"未来戦略室長には毎日絵本を読んであげて好感度を高めて、","ENG":"And she won the Future Strategy Department head's favor by reading her fairy tales every day.","TWN":"還天天讀童話書給未來戰略室的室長聽，博取室長的歡心，"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L47_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"믿었던 부사장님은 최저 생계비만 있으면 된다니까 올해의 우수사원으로 추천하셨죠.","JPN":"ハードルが高い副社長には最低の賃金でいいと言って、今年の優秀社員に推薦されましたね。","ENG":"Not to mention the Vice President... who recommended her as the Employee of the Year when she said she'd be happy with minimum wage.","TWN":"而且連副總都推薦她為今年的優秀員工，還說只要有可維持生計的錢就行了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"너무 잘 지내서 오히려 수상하지 않나요?","JPN":"あまりにも順調でちょっと怪しいと思いませんか？","ENG":"If anything, she's getting adjusted too well. It's almost suspicious.","TWN":"她和每個人相處的都這麼好，你不覺得很奇怪嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"꼭 그런 계통의 훈련이라도 받은 것 같던데요.","JPN":"まるでそういう系統の訓練でも受けたようにも見えて。","ENG":"It's as if she's been trained to be like that.","TWN":"就好像接受過這方面的專業訓練一樣。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는 다른 분들의 고민을 이해하려고 노력할 뿐입니다, 샤오린님. 오해는 말아 주시길.","JPN":"私は他の方の悩みを理解しようと努力するだけでございます、シャオリン様。くれぐれも誤解なきようよろしくお願いします。","ENG":"I simply strive to understand what troubles others, Ms. Xiao. I hope that resolves any misunderstanding.","TWN":"我只是想儘量去理解別人而已，請您不要誤會，曉琳小姐。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"제 얘기를 엿듣고 있었어요?","JPN":"私の話を盗み聞きしていたんですか？","ENG":"You were eavesdropping on me?","TWN":"妳在偷聽我說話？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께 일정을 말씀드리려다 그만...... 죄송합니다.","JPN":"ご主人様に予定を報告しようとお邪魔したところつい……申し訳ございません。","ENG":"I'm sorry... I was simply waiting to brief the Master on the schedule.","TWN":"抱歉……我只是想來給主人報告日程的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자, 자. 그만하게. 같은 회사에서 일하는 사이에.","JPN":"まあまあ、その辺にしよう。同じ会社で働く仲間としてな。","ENG":"Now, now. That's enough. You guys are colleagues.","TWN":"好了，好了，不要說了，大家都是同事。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"베로니카 양, 내게 말하려던 일정이 뭔가?","JPN":"ベロニカ、予定とは？","ENG":"So what were you going to brief me about, Veronica?","TWN":"貝洛妮卡，妳繼續吧。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네, 주인님. 외부 업체 관계자와의 미팅입니다.","JPN":"はい、ご主人様。外部業者の関係者とのミーティングです。","ENG":"It's a meeting with an industry associate, Master.","TWN":"主人，接下來需要和外部公司的負責人開個會。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런 일은 부사장에게 맡기게. 난 회사와 직원들의 미래를 걱정하기도 바쁜 몸이야.","JPN":"そんなことは副社長に任せてくれ。私は会社や社員たちの将来の心配で忙しい身でね。","ENG":"Leave that to the Vice President. I'm busy enough taking care of our own staff and their future.","TWN":"那種事就讓副總做吧，我光是擔心公司和員工的未來就已經不得閒了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"부사장님께선 오늘 아침 급히 출장을 나가셨습니다.","JPN":"副社長は今朝急遽出張に行かれました。","ENG":"Vice President Lee had to go on an urgent business trip this morning.","TWN":"副總今天早上急急忙忙出差去了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"<color=#ffd34c>남에게 떠넘길 생각 말고 가끔은 진짜 일을 하라</color>고 하시더군요.","JPN":"<color=#ffd34c>他人任せはいい加減にして、たまにはちゃんと仕事らしい仕事をしてください</color>とのことです。","ENG":"She said, <color=#ffd34c>\\"Once in a while, you should do some real work instead of making others do it for you.\\"</color>","TWN":"副總說，<color=#ffd34c>別老是想著把工作丟給別人，做好自己的事。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......제길. 내 생각을 읽고 선수 쳤군.","JPN":"……くう。先読みされたか。","ENG":"Dang it. So she read my mind and beat me to it.","TWN":"……可惡，居然先下手為強。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"좋아. 어디 얼굴이나 보기로 하지.","JPN":"いいだろう。どんな人なのか会ってみようじゃないか。","ENG":"Fine, I guess I'll go see whoever it is I need to see.","TWN":"好吧，那就去露個臉吧。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 수행해 드리겠습니다.","JPN":"はい、お付き添いさせていただきます。","ENG":"Yes, Master. I will accompany you.","TWN":"好的，那我去準備。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"앗! 외출이심까? 모네도 따라가고 싶슴다!","JPN":"あれ？　外出っすか？　モネもついて行きたいっす！","ENG":"Oh! Are you going out, sir? I'd love to tag along if that's alright!","TWN":"啊！是要外出嗎？莫妮也想去！"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"오오~ 정말 으리으리한 도시지 말임다~","JPN":"うおお～本当におっきい都市っすね！","ENG":"Ooh! This city sure is fancy!","TWN":"哇~真是個金碧輝煌的城市啊~"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"주인님! 저희도 저런 높은 빌딩으로 이사 가는 검다!","JPN":"ご主人様！　モネたちもあんな高いビルに引っ越したいっす！","ENG":"Master! Why don't we move into a huge building like that?","TWN":"主人！我們也搬到那麼高的房子裡吧！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하, 모네 양. 우린 지금 건물 임대료 내기도 빠듯하다네.","JPN":"ハハハ、モネ。我が社は今いる場所の賃貸料だけでも精一杯だぞ。","ENG":"Hah hah. Mone, we can barely afford our current rent.","TWN":"哈哈，莫妮啊，我現在連我們那棟樓的租金都交不起呢。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이번 미팅 상대는 알파트릭스 그룹의 방위산업부 지사장입니다.","JPN":"今回のミーティングの相手はアルファトリックスグループの防衛産業部の支社長です。","ENG":"You'll be meeting the branch chief of the Alphatrix Group's Defense Industries Directorate.","TWN":"這次會議，會由阿爾法崔克斯集團的國防產業部長參加。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"입맛이 까다로운 편이라고 해서 특별히 평판이 좋은 레스토랑을 예약해 뒀습니다.","JPN":"かなり舌が肥えている方とお聞きしたので、評判の良いレストランを予約させていただきました。","ENG":"I heard he's a rather picky eater, so I've made a reservation at a particularly reputable restaurant.","TWN":"聽說那位的口味比較挑剔，所以我特意預約了一個口碑很不錯的餐廳。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 그런 정보를 어디서 얻었나?","JPN":"おお、そんな情報はどこで手に入れたんだ？","ENG":"Oh, where did you find that out?","TWN":"噢？妳是從哪裡得來的情報？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마트에서 장을 보다가 단서를 얻었습니다.","JPN":"スーパーでお買い物中に聞きました。","ENG":"While grocery shopping.","TWN":"我去逛超市的時候聽到的。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"미팅 상대 분의 아내 분께 과일 고르는 법을 알려 드리면서 접근해 정보를 얻었죠.","JPN":"先方の奥様に果物の選び方を教えながら接近して、情報を入手しました。","ENG":"I approached his wife at the grocery store and helped her pick out ripe fruit in order to extract the intel.","TWN":"我故意接近他的夫人，教她如何挑水果，順便就問出來了。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 그거 정말 믿을 만한 정보로군.","JPN":"そ、それは実に信頼できる情報だな。","ENG":"W-well, that sure sounds reliable.","TWN":"那、那真是可靠的情報啊。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러고 보니 이제 곧 계약 기간도 끝인데......","JPN":"そういえばそろそろ契約が終わるんだが……","ENG":"Come to think of it, your contract is going to expire soon...","TWN":"對了，妳們的合約也快到期了……"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"다른 거래처는 아직 안 정해졌나?","JPN":"次の取引先はまだ決まっていないのかね？","ENG":"Have you decided on where you'll work next?","TWN":"找到下一家了嗎？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"부끄럽지만 그렇습니다. 메이드로서 미흡하기 때문이겠죠.","JPN":"恥ずかしながら、左様でございます。メイドとしてまだ未熟なせいでしょう。","ENG":"I'm ashamed to admit that I have not. I suppose it's all because my capabilities as a maid fall far too short.","TWN":"還沒有，可能是我作為女僕還有很多不足的地方。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 역시 우리와 계약 기간을 연장하는 건","JPN":"ならばやはりうちと契約期間を延長するのは……","ENG":"Then how about extending your contract with our","TWN":"那還是和我們續約…"},"stage":{"bg":"VEHICLE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......뭐, 뭐지?","JPN":"ん、何だ？","ENG":"— ... W-what was that?","TWN":"……怎、怎麼了？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_EARTHQUAKE"},{"id":"L44_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"주인님! 저기 도로가 쩍쩍 갈라지고 있슴다!","JPN":"ご主人様！　向こうから道路がバキッと割れてきてるっす！","ENG":"Master! The road is splitting in two!","TWN":"主人！那邊的道路都裂了！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"피하기엔 늦었어요! 두 분 다 뭔가 붙잡으세요!","JPN":"間に合いません！　二人とも何かに掴まってください！","ENG":"It's too late—we're going to crash! Both of you, hold onto something!","TWN":"來不及躲了！你們快抓住什麼東西，不要掉下去！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내드립니다. 현재, 일부 구역에서 기준치를 뛰어넘는 침식파가 검출되었습니다. 시민 여러분은 즉시 대피해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>ご案内します。現在、一部区域で基準値を超える侵食波が検出されました。市民の皆様はただちに避難してください。</color>","ENG":"<color=#ffd34c>Attention. Dangerous levels of Corruption Rays have been detected in several sectors. Please evacuate immediately.</color>","TWN":"<color=#ffd34c>通知，目前部分地區檢測出超過標準值的侵蝕波，請各位市民立即躲避。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내...... 니다. ......에서 ......를 뛰어넘는...... 시민 여러...... 즉시 대피......</color>","JPN":"<color=#ffd34c>ご案内……します。……で……を超える……市民の皆様……ただちに避難……</color>","ENG":"<color=#ffd34c>Atten... detected... several sec... please evac... mediately...</color>","TWN":"<color=#ffd34c>通知……部分……檢測……超過……請各位市民……躲避……</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"콜록, 콜록......! 열렸슴다, 메이드장님!","JPN":"ゲホ、ゲホ……！　開いたっす、メイド長！","ENG":"*Cough, cough* I got the door open, ma'am!","TWN":"咳咳，咳咳……！打開了，女僕長大人！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으윽. 카메라가 빙빙 도는군. 조리개가 고장난 모양이야.","JPN":"うう、目がグルグル回るな。カメラが故障したみたいだ。","ENG":"Ugh... My camera's all out of focus. Its aperture must be malfunctioning.","TWN":"額，相機一直在轉，看來是光圈壞了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이게 바로 직원 분들이 말씀하시던 침식 재난이군요......","JPN":"これが皆様がおっしゃっていた侵食災害ですね……","ENG":"So this must be the Corruption Disaster your employees were talking about...","TWN":"這就是同事們說的侵蝕災難嗎……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"실제로 보니 더 끔찍하네요.","JPN":"実際に見ると、本当に無惨ですね。","ENG":"It's even more horrific than I imagined.","TWN":"比想像中還要可怕。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"치, 침식체임다! 사방에 온통 멸치처럼 득실거리고 있슴다!","JPN":"し、侵食体っす！　あちこちから湧いてくるっす！","ENG":"C-Corrupted Objects! They're swarming us like a school of shrimp!","TWN":"侵、侵蝕體！四面八方都是侵蝕體啊！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"방송에서 나온 것보다 규모가 크군. 방주를 회수한 영향인가......?","JPN":"放送より規模が大きい。箱舟を回収した影響なのか……？","ENG":"There're a lot more of them than the announcement said. Could this be the impact from retrieving the Ark?","TWN":"這規模比通知裡說的還要龐大。是因為回收了方舟嗎……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"대피소를 찾아 봐야겠군요.","JPN":"避難所を探さなければなりませんね。","ENG":"We'd better find a shelter.","TWN":"看來需要找找避難所了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"사장님, 그리고 모네. 제 옆에 꼭 붙어 계세요.","JPN":"社長、そしてモネ。私から離れないでください。","ENG":"Both of you, please stay right behind me.","TWN":"老闆，還有莫妮，一定要寸步不離地跟著我。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"조심하게. 총을 쓸 줄 안다고 해서 함부로 자극하다간 더 크게 당할 수도 있어.","JPN":"気を付けたまえ。銃を使えるとは言え、むやみに敵を刺激すると反撃されることもある。","ENG":"Be careful. You might provoke them if you start shooting blindly.","TWN":"小心點，即使會用槍也不要刺激他們，一不小心就會被他們攻擊。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당부해 주셔서 감사합니다.","JPN":"ご助言ありがとうございます。","ENG":"Thank you for your advice.","TWN":"感謝您的提醒。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 탄도학과 유격전술 역시 메이드의 기본 소양. 호위가 소홀하진 않을 테니 안심하시길.","JPN":"ですが弾道学と遊撃戦術はメイドの基本素養。護衛を粗忽にすることはございませんのでご安心ください。","ENG":"But like every maid, I am adept in firearms and tactics. Fret not, for I will keep you safe.","TWN":"不過，射擊技巧和遊擊戰術是女僕必備的基本素養，我會保護你們的，放心。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아니, 내가 아는 메이드의 소양과는 전혀 다르네만......?","JPN":"いや、私の知っているメイドの基本素養とはかなりかけ離れている気がするんだが……？","ENG":"Um... Since when did maids get training in firearms and tactics?","TWN":"什麼？這跟我知道的女僕的基本素養好像完全不一樣啊……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"침식체들이 뿔뿔이 흩어지지 않은 지금이 여길 벗어날 수 있는 기회입니다. 이쪽으로 오시죠.","JPN":"侵食体がまだ集まっている今がここから離れられるチャンスです。こちらへどうぞ。","ENG":"This is our chance to get away since they haven't spread out yet. Please come this way.","TWN":"侵蝕體還沒有四處分散，現在是我們逃離這裡最好的機會，快來這裡。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"반드시...... 주인님께는 생채기 하나 생기게 하지 않겠습니다.","JPN":"必ず……ご主人様に傷一つ残さないように尽力します。","ENG":"I won't let them leave so much as a scratch on you, Master.","TWN":"我發誓……不會讓主人您受到任何傷害。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};